(63, 'Label & Stickers', 'printed-labels-stickers', 'Label And Stickers', 'Label And Stickers', 'Label And Stickers', '<p>lorem ipsum dollar sumit&nbsp;Label &amp; Stickers</p>', '112', '1623828952.display.jpg', NULL, 'label-and-stickers.jpg', NULL, 1, 0, '1623828952.favicon.png', NULL, NULL, NULL),
(64, 'Gift Boxes', 'gift-boxes', 'Gift Boxes | Over 100 Sizes, Styles & Colours In Stock', 'Gift boxes are made with sustainable materials. PremiumBoxes offers these boxes several customization options following the clients’ needs.', 'Gift Boxes, gift boxes packaging, Sustainable packaging, personalized gift boxespersonalized gift boxes', '<h1><span style=\"font-size:20px\"><strong><span style=\"color:#000000\">Personalized Gift Boxes</span></strong></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Gift boxes are made with eco-friendly materials such as cardboard, kraft, corrugated cardboard, and paper stocks. PremiumBoxes offers various customization options for these boxes. The size, style, shape, and design of these boxes are customizable, following the clients&rsquo; preferences. Advanced printing techniques along with CMYK and PMS color schemes are used for these boxes. Finishing options such as soft-touch, spot UV, matte, glossy, and smudge-free are available. The clients can choose to get die-cut windows, handles, and placeholders added to these boxes if needed.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Gift boxes</strong>&nbsp;are used across the globe on various occasions. PremiumBoxes offers&nbsp;<strong>gift box packaging</strong>&nbsp;with customizations preferences chosen by the clients.&nbsp;</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Customizable Packaging Solutions</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer various customization options for&nbsp;<strong>custom gift boxes</strong>. Clients can choose the size, style, shape, and design of the boxes following their needs.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Affordable for Everyone</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We understand that&nbsp;<strong>gift boxes packaging</strong>&nbsp;is a common need. To facilitate a maximum number of clients, we strive hard to keep our prices the lowest. We also offer special discounts on large volume orders.&nbsp;</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Sustainable Packaging</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes understands corporate social responsibility and manufactures all the products using organic supplies only. Cardboard, corrugated, kraft, and paper stocks, along with plant-based inks, are used for the manufacturing and printing of these boxes.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer complimentary design support to our clients. A 2D or 3D mockup of their personalized gift boxes design idea is available for free.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Doorstep Delivery</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free doorstep delivery for standard orders of&nbsp;<strong>gift boxes</strong>&nbsp;across North America. Shipping for clients in other parts of the world is also available.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Exclusive Features</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">The following are some more features that make us unique among the competitors.</span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"color:#000000\">Minimum 100 boxes</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"color:#000000\">Fastest turnaround time</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"color:#000000\">Professional customer care</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"color:#000000\">Safe and easy payment options</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"color:#000000\">No die-cut or plate charges</span></li>\r\n</ul>', '110', '1782908839-Gift-Boxes.webp', NULL, '1782908839-b-Gift-Boxes.webp', NULL, 1, 0, '1623829266.97759-business-card-boxes-cardboard.jpg', NULL, 'ihadshfaksdfiosdfiods', '1782908839-h-Gift-Boxes.webp'),
(67, 'Retail Boxes', 'retail-boxes', 'Retail Boxes | Retail Packaging Suppliers, Cardboard Boxes', 'Retail boxes are the need of every business. PremiumBoxes offers them at affordable prices with several customization options and free shipping.', 'Retail Boxes, retail packaging, retail boxes packaging, retail cardboard boxes, wholesale gift boxes, empty gift boxes, retail packaging suppliers', '<h1 style=\"margin-left:0.0001pt; margin-right:0px; text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Retail Packaging</strong></span></span></h1>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\"><strong>Retail boxes</strong>&nbsp;are used in every business. They are customizable according to the needs of the products. PremiumBoxes manufactures these boxes with cardboard, kraft, corrugated, and paper stocks. The latest printing techniques, along with CMYK and PMS color schemes, are used for these boxes. Various finishing styles are also available. The shape, design, size, and thickness of the manufacturing materials are customizable as per clients&rsquo; needs. Custom inserts, placeholders, die-cut windows, and other add-ons are also available for these boxes.</span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\"><strong>Retail boxes</strong>&nbsp;are mostly used in the food, cosmetics, jewelry, and clothing industries. They are available in customizable shapes and sizes at PremiumBoxes. Custom inserts, placeholders, die-cut windows, and handles can also be added to these boxes.</span></p>\r\n\r\n<h2 style=\"margin-left:0.0001pt; margin-right:0px; text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Vivid Printing &amp; Finishing</strong></span></span></h2>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\">We use the latest technologies along with PMS and CMYK color schemes for the printing of&nbsp;<strong>retail packaging</strong>. All the inks and adhesives used for these boxes are 100 percent plant-based. Also, we offer various finishing options, including glossy, matte, smudge-free, soft-touch, spot UV, and embossing.</span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Get the Lowest Prices</span></span></strong></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers&nbsp;<strong>retail boxes packaging</strong>&nbsp;at amazingly low prices. We keep the pricing lowest to facilitate the clients from different industries. Volume discounts on larger orders are also available.</span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free &amp; Trackable Shipping</strong></span></span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\">We offer free shipping services for clients across the United States of America and Canada. Shipping for international clients is also available on request. Online tracking of the order is also an option.</span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>100% Customer Satisfaction</strong></span></span></p>\r\n\r\n<p style=\"margin-left:.0001pt; margin-right:0; text-align:justify\"><span style=\"color:#000000\">PremiumBoxes believes in 100 percent customer satisfaction. Our vigilant customer care team serves the clients at every step. Also, we are available to our clients through e-mail, dedicated chat support, and call. A request for a callback is also an option to reach us.</span></p>', '110', '1782908952-Retail-Boxes.webp', NULL, '1782908952-b-Retail-Boxes.webp', NULL, 1, 1, '1623830378.97759-business-card-boxes-cardboard.jpg', 'Retail Boxes', 'Discover our premium retail box collection, designed to elevate your brand and create a lasting impression. Our custom retail packaging combines durability, functionality, and eye-catching designs to showcase your products beautifully.', '1782908952-h-Retail-Boxes.webp'),
(76, 'Cosmetic Boxes', 'cosmetic-boxes', 'Cosmetic Boxes | Cosmetics packaging, Makeup Packaging', 'PremiumBoxes manufactures immaculate cosmetic boxes with organic materials that are known for their perfection and sustainability.', 'cosmetic box packaging suppliers, cosmetic packaging, cosmetic boxes, custom cosmetic boxes, cosmetics packaging boxes', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Cosmetic Packaging</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Cosmetic boxes</strong>&nbsp;are made with organic materials that include cardboard, kraft, and paper stocks. PremiumBoxes offers these boxes with astonishing customization options. Clients can choose their shape, style, and size according to their needs. Advanced printing techniques along with various finishing options are also available. Die-cut window handles, and inserts can also be added to these boxes as per convenience.&nbsp;&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>The cosmetics packaging supplies</strong>&nbsp;industry is worth around USD50 billion, according to a report by Market Research Future. PremiumBoxes is among the major&nbsp;<strong>cosmetic box packaging suppliers</strong>&nbsp;in the United States of America.</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Eco-friendly Packaging Solutions</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">All the products at PremiumBoxes are made with 100 percent organic and recyclable supplies. Cardboard, kraft, and paper stocks are used for the manufacturing of&nbsp;<strong>cosmetic packaging</strong>&nbsp;solutions. The inks and adhesives used for manufacturing our&nbsp;<strong>cosmetic boxes&nbsp;</strong>are plant-based.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Affordable Pricing with Secure Payment Options</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">The pricing for our cosmetics packaging boxes is the lowest as compared to the market. Also, all payment transactions are made only through secure and trusted channels.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Thorough Customization Options</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer maximum customization options for&nbsp;<strong>custom cosmetic boxes</strong>. Clients can make a choice of size, style, design, shape, and thickness of the manufacturing materials as well.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Finest Printing with Free Design Support</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use the latest printing methods along with CMYK and PMS color schemes for these boxes. Also, we offer free design support along with 2D or 3D mockups.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes provides free shipping for standard orders across North America. Rush delivery service is also available on request.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Professional Customer Care</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Customer care service for the assistance of clients is readily available through chat portal, e-mail, and call. Feel free to communicate with us at any time.</span></p>', '110', '1782909108-Cosmetics-Boxes.webp', NULL, '1782909108-b-Cosmetics-Boxes.webp', NULL, 1, 1, NULL, NULL, NULL, '1782909108-h-Cosmetics-Boxes.webp'),
(77, 'Eco Friendly Boxes', 'eco-friendly-boxes', 'Eco Friendly Boxes | Biodegradable Packaging | Green Packaging', 'Eco-friendly Boxes are becoming popular across the globe. PremiumBoxes offers these boxes with amazing customization options and free shipping.', 'Eco Friendly Boxes,  Biodegradable Packaging, Green Packaging, Eco-friendly Packaging', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Eco-friendly Boxes | Biodegradable Packaging&nbsp;</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Eco-friendly Boxes are the new face of the packaging industry. These boxes are used in food, cosmetics, personal hygiene, and many other diligences. PremiumBoxes manufactures these boxes with recyclable supplies. The inks used for the printing of our products are plant-based. Along with the best quality, we offer highly affordable pricing. Volume discounts are also available for larger orders. The clients can get these boxes in various customizable sizes, shapes, and styles. Finishing options including matte, glossy, spot UV, soft-touch, and smudge-free are also available.<br />\r\n&nbsp;<br />\r\nPremiumBoxes is offering Eco-friendly Boxes in the USA to facilitate all types of industries. The food, beverages, and cosmetics industries are among the major consumers of eco packaging.</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">End to End Customizations</span></span></strong></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">The size, design, shape, and style of these boxes are customizable, following the clients&rsquo; needs. The choice of different manufacturing materials, along with variations in their thickness, is also available.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><strong><span style=\"color:#000000\">Vivid Printing with Design Support</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes uses the latest techniques for the manufacturing and printing of its products. The clients can share their eco-friendly packaging ideas with us and get free design support.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><strong><span style=\"color:#000000\">Free Doorstep Delivery</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer free-of-cost doorstep delivery across the USA and Canada. Shipping for international clients is also available.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><strong><span style=\"color:#000000\">Enjoy the Lowest Pricing</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Eco-friendly boxes are available at the lowest pricing at PremiumBoxes. We strive to keep the prices low to facilitate clients belonging to all walks of life.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><strong><span style=\"color:#000000\">Customer Care Services</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We provide our clients with professional assistance at every step. The clients can get connected with us through calls, e-mail, and our dedicated chat portal.</span></p>', '110', '1782909216-Eco-Friendly-Boxes.webp', NULL, '1782909216-b-Eco-Friendly-Boxes.webp', NULL, 1, 1, NULL, NULL, NULL, '1782909216-h-Eco-Friendly-Boxes.webp'),
(79, 'Metalized Boxes', 'metalized-boxes', 'Metalized Boxes | Gold Foil Boxes, Silver Foil Boxes', 'Metalized boxes are fancy yet economical packaging solutions. PremiumBoxes offers various customizations for these boxes with free design support.', 'Metalized Boxes, Gold Foil Boxes, Silver Foil Boxes, metalized packaging,', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><strong><span style=\"color:#000000\">Metalized Packaging</span></strong></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Metalized boxes are fancy and sturdy packaging solutions. Their metalized look makes them prominent and inevitable for high-value products and gift items. They are made with green and nature-friendly supplies. PremiumBoxes offers end-to-end customization options for these packages. The clients can choose the shape, style, design, color scheme, and size of these boxes. Different add-ons such as inserts, dividers, placeholders, and handles can also be added to these boxes. To enhance their visual appeal and safety features, various types of finishing options are also available. Volume discounts along with free shipping are also offered for these boxes.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Products packed and presented in&nbsp;<strong>gold foil boxes</strong>&nbsp;are considered more valuable and quickly get noticed by the customers as compared to the others. These boxes are available at PremiumBoxes with various exclusive features.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Lowest Prices</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers the lowest prices for&nbsp;<strong>metalized packaging</strong>. For large quantity orders, volume discounts are also available. Special discounts are also offered occasionally.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Get the Best Customizations</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Different types of customization options are offered for&nbsp;<strong>custom metalized packaging boxes</strong>. These options include the choice of style, size, shape, and manufacturing material. Foiling options for these boxes include gold, silver, and copper foiling.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free shipping of&nbsp;<strong>metalized boxes</strong>&nbsp;across the USA and Canada. Rush delivery option is also available on demand.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Contact us</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We are available to assist our clients via a dedicated chat portal, e-mail, call, and request a callback. Get in touch with us to enjoy the finest packaging solutions at the lowest pricing.</span></p>', '110', '1782908794-Metalized-Boxes.webp', NULL, '1782908794-b-Metalized-Boxes.webp', NULL, 1, 1, NULL, NULL, NULL, '1782908794-h-Metalized-Boxes.webp'),
(80, 'Display Packaging', 'display-packaging', 'Display Packaging', 'Display Packaging', 'Display Packaging', '<p>Display Packaging</p>', '110', '1782909019-Display-Packaging.webp', NULL, '1782909019-b-Display-Packaging.webp', NULL, 1, 1, NULL, NULL, NULL, '1782909019-h-Display-Packaging.webp'),
(81, 'Food Boxes', 'food-boxes', 'Food Boxes', 'Food boxes are essential for food safety and presentation. PremiumBoxes offers a wide range of food-grade boxes at affordable prices.', 'Food Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Food boxes&nbsp;</strong>manufactured with organic materials are the necessity of every food business. Various materials such as corrugated, Kraft, and cardboard stocks are used to manufacture these boxes. They have customizable shapes and designs. PremiumBoxes uses the latest printing techniques along with CMYK and PMS color schemes for these boxes. Various finishing options such as matte, foil stamping, and spot UV are used for these boxes. Inserts, dividers, and holders can also be added. PremiumBoxes offers the best packaging solutions for a diverse range of products.&nbsp;</span></p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Essential Safety Features</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers top-class safety features for food and&nbsp;<strong>beverage packaging&nbsp;</strong>solutions. Various add-ons such as holders and dividers are also offered following the clients&rsquo; needs.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Food-grade Materials</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes uses organic and food-grade materials such as cardboard, Kraft, and corrugated stocks for the manufacturing of these boxes. The clients can choose the manufacturing material as well as its grade and thickness.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Diverse Customization Options</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer numerous customizations to design and make the most innovative&nbsp;<strong>custom food boxes</strong>. Customizations in size, design, shape, and style are available for these boxes.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Printing with Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use the latest printing techniques for&nbsp;<strong>custom printed food boxes</strong>. CMYK and PMS color schemes are used for these boxes. Free design support along with 2D and 3D mockups is also available.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Shipping for all</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free shipping to all clients across the United States of America and Canada. Rush delivery is also provided on request. Shipping for international clients is also available.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Professional Customer Care</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer customer care service through various mediums such as e-mail, call, call back, and dedicated live chat portal. Our representatives assist the clients professionally at every step.</span></p>', '110', '1782909151-Food-Boxes.webp', NULL, '1782909151-b-Food-Boxes.webp', NULL, 1, 1, NULL, NULL, NULL, '1782909151-h-Food-Boxes.webp'),
(82, 'Luxury Boxes', 'luxury-boxes', 'Luxury Boxes', 'Luxury Boxes', 'Luxury Boxes', '<p>Luxury Boxes</p>', '110', '1782909260-Custom-Luxury-Boxes.webp', NULL, '1782909260-b-Custom-Luxury-Boxes.webp', NULL, 1, 0, NULL, NULL, NULL, '1782909260-h-Custom-Luxury-Boxes.webp'),
(83, 'CBD Packaging', 'cbd-packaging', 'CBD Packaging', 'CBD Packaging', 'CBD Packaging', '<p>CBD Packaging</p>', '110', '1782908889-CBD-Boxes.webp', NULL, '1782908889-b-CBD-Boxes.webp', NULL, 1, 0, NULL, NULL, NULL, '1782908889-h-CBD-Boxes.webp'),
(85, 'Apparel Boxes', 'apparel-boxes', 'Apparel Boxes, Boxes for T-Shirts, Ties, and Clothing', 'There are numerous catchy designs of apparel boxes available at PremiumBoxes. Get them with amazing deals such as free shipping and design support.', 'Apparel Boxes, Custom Boxes, Clothing gift boxes, Clothing packaging Boxes, custom packaging boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Different designs of&nbsp;<strong>apparel boxes</strong>&nbsp;are available at PremiumBoxes. They come in numerous attractive shapes and colors. Clients can also get them in any size according to their needs. Placeholders, custom inserts, and die-cut windows can be added to these boxes on demand. Their manufacturing materials are organic and biodegradable. These materials include kraft, bux board, and cardboard stock. Many customization options, such as additional coatings and laminations, are available. Modern printing technologies are used for the printing of these boxes. Free shipping is available across the USA and Canada. Free design support is also available.<strong>&nbsp;</strong></span></p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Eco-friendly Materials</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We manufacture environmentally-friendly&nbsp;<strong>kraft apparel boxes</strong>. They are biodegradable and recyclable. Other supplies such as inks and adhesives used in their manufacturing are also environmentally friendly.<strong>&nbsp;</strong></span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Cost-effective Packaging</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes keeps the pricing of these boxes the lowest. However, the low pricing does not mean that we do not know how to manufacture&nbsp;<strong>luxury apparel boxes</strong>. We are known for providing the finest packaging at the lowest pricing.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Shipping&nbsp;</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We are offering free shipping across North America. Shipping is also available for international clients on demand. We also offer rush delivery under special terms and conditions.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Free design support for&nbsp;<strong>apparel packaging</strong>&nbsp;is available for clients. It includes making changes in a standard design as well as making a new design from scratch. A 2D or 3D mockup of the design is also available on demand.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>The Best Quality Printing</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use modern printing technologies along with PMS and CMYK color schemes for the printing of&nbsp;<strong>apparel packaging boxes.</strong>&nbsp;<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Astonishing Customization Options&nbsp;</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers numerous customization options for these boxes. Clients can ask for any size, shape, color scheme, and style. Compartments, die-cut windows, handles, or placeholders can also be added on demand. Many finishing options such as coatings, stamp foiling, embossing, and others are available.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Customer Care Service</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We provide customer care service for assisting our clients. Contact us for assistance through email, live chat, and call.</span></p>', '110', '1782909070-Apperal-Boxes.webp', NULL, '1782909070-b-Apperal-Boxes.webp', NULL, 1, 0, NULL, NULL, NULL, '1782909070-h-Apperal-Boxes.webp'),
