(1, 'About Us', 'about-us', 'About Us', '<p><span style=\"font-size:18px\"><u><strong>About Us</strong></u></span></p>\r\n\r\n<p>We work closely with our clients, getting to know what you need - the outcomes you want to see, the goals you&#39;re aiming to achieve and then we make it happen.</p>\r\n\r\n<p>We work closely with our clients, getting to know what you need - the outcomes you want to see, the goals you&#39;re aiming to achieve and then we make it happen.</p>', 'About Us', 'About Us', 'About Us', '16275598002034209575.About Us.jpg', 'About Us', 1, 1, 2),
(4, 'Our Blog', 'our-blog', 'Our Blog', '<p>Our Blog</p>', 'Our Blog', 'Our Blog', 'Our Blog', '1627559827697110175.Our Blogs.jpg', 'Our Blog', 2, 1, 2),
(8, 'Contact Us', 'contact-us', 'Contact Us', '<p>In case you some aquestions popped in your&rsquo;s mind,<br />\r\nFeIn case you some aquestions popped in your&rsquo;el email or even visit us.</p>', 'Contact Us', 'Contact Us', 'Contact Us', '16275640751550982462.Contact Us.jpg', 'Contact Us', 3, 1, 2),
(9, 'Request Quote', 'request-quote', 'Request Quote', '<p>Request Quote</p>', 'Request Quote', 'Request Quote', 'Request Quote', '162756411115700588.Request Quote.jpg', 'Request Quote', 2, 1, 2),
(10, 'Terms of Services', 'term-and-services', 'Terms of Services', '<p>Coming Soon!</p>', 'Terms of Services', 'Terms of Services', 'Terms of Services', '16275642511712456377.terms-of-services.jpg', 'Terms of Services', 1, 1, 3),
(11, 'Privacy Policy', 'privacy-policy', 'Privacy Policy', '<p>Coming Soon!</p>', 'Privacy Policy', 'Privacy Policy', 'Privacy Policy', '16275641901824619754.PRIVACY-POLICY.jpg', 'Privacy Policy', 6, 1, 3),
(12, 'Home', '/', 'Home', NULL, 'Premium Boxes | Top Custom Packaging Manufacturer in the USA', 'Custom boxes are famous in the packaging industry for their remarkable capabilities. Also, our rigid boxes are one of a kind and provide ultimate protection.', 'Custom Packaging,  Custom Boxes, Premium Boxes, Cardboard Boxes, Wholesale Packaging', NULL, 'Custom Box Packaging', NULL, 0, 0),
(13, 'Register', 'user-register', 'Register', NULL, 'Register', 'Register', 'Register', NULL, NULL, NULL, 1, 0),
(16, 'User Login', 'user-login', 'User Login', NULL, 'User Login', 'User Login', 'User Login', NULL, NULL, NULL, 1, 0),
(18, 'User Dashboard', 'user-dashboard', 'Job-Seeker Dashboard', NULL, 'Job-Seeker Dashboard', 'Job-Seeker Dashboard', 'Job-Seeker Dashboard', NULL, NULL, NULL, 1, 0),
(19, 'Searched Products', 'search', 'Searched Products', NULL, 'Searched Products', 'Searched Products', 'Searched Products', '16238271651394546031.bg_6.jpg.webp', 'search', NULL, 0, 0),
(20, 'Job-Seeker Edit Profile', 'jobseeker/editprofile', 'Job-Seeker Edit Profile', NULL, 'Job-Seeker Edit Profile', 'Job-Seeker Edit Profile', 'Job-Seeker Edit Profile', '', NULL, NULL, 0, 0),
(22, 'Job-Seeker Account Information', 'jobseeker/account_information', 'Job-Seeker Account Information', NULL, 'Job-Seeker Account Information', 'Job-Seeker Account Information', 'Job-Seeker Account Information', '', NULL, NULL, 0, 0),
(28, 'Search Blog', 'blogsearch', 'Search Results', NULL, 'Search Results', 'Search Results', 'Search Results', '', NULL, NULL, 0, 0),
(31, 'Delivery Information', 'delivery-information', 'Delivery Information', '<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#4a6ee0\">www.premiumboxes.com</span><span style=\"color:#0e101a\">&nbsp;offers free of cost, safe, and reliable shipping options all over the United States. In addition, we also offer delivery services all over the world with minimal charges. We guarantee that our delivery options will be affordable and there will be no compromise on the time limit.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We generally offer two types of delivery plans to our customers. The difference lies in the charges and the total time required to deliver the order to the desired location. Following are our two options for the clients.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\">&nbsp;</span><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">Standard Shipment Plan</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Our standard delivery plan is available for free, and it takes a total of 8-10 business days to complete the order delivery. Our standard delivery services are available for clients all over the United States of America.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">Expedited Shipment Plan</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">For the customers who want the orders to be delivered to their doorstep a bit earlier, they can use our rush delivery plan. This plan makes sure to deliver the order to your doorstep in a maximum of 4-6 working days. However, the clients will have to pay a minimal amount for the expedited delivery.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">Note:</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">While reading the details about the delivery plans in the above lines, you must have read the word &ldquo;Business Days.&rdquo; Our business days exclude Saturdays, Sundays, and other public holidays. Therefore, we request our valuable customers to keep a closer eye on the calendar as well to save themselves from any inconvenience.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Our shipping staff makes sure to deliver the order to the designated location at the earliest. It is the responsibility of the receiver to remain attentive on the delivery day and receive the order. If the customer is unable to receive the products at the designated time, the company will not be considered liable for any delay.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">The doorstep-delivery feature is available for urban areas only. If you are in a remote place and want the order to be delivered right to your place, you will have to pay for the charges accordingly if the shipping company asks so.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">In addition, if you had given the wrong address details or there is some kind of delay from your side as far as the receiving is concerned, you will have to inform us. You must let us know about the situation, and we must receive a notification for the re-delivery of the order within the first 6 days. Besides, you will also have to bear the additional delivery charges in such situations.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We are partners with the top-ranked and secure shipping service providers. We always are our best to deliver the products in their finest condition. However, if due to some unavoidable and natural reasons there is a delay in delivery or damage to the products, the company is not responsible.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Delivering the order at your doorstep within the due time is our main responsibility. In case of any unexpected and natural occurrence, we will inform you at the earliest, and we will keep in touch with you till further processing. In case of a faulty payment process, the company has all the right to pause the delivery process till the payments are cleared by the customers.</span></span></p>', 'Product Shipment Information | When You\'ll Get Your Product', 'Product Shipment Information | When You\'ll Get Your Product', 'Product Shipment Information, When You\'ll Get Your Product, Premium Boxes', '1627564287983118031.delivery-inforamtion.jpg', 'Delivery Information', 8, 1, 3),
(32, 'Return Policy', 'return-policy', 'Return Policy', '<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We know the value of customer satisfaction in a business, and we make sure to keep our clients satisfied in the best possible manner. We offer a comprehensive return policy for our customers if a mishap occurs during the order processing and delivery process.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">You can let us know if there is an issue with the delivered products. If you find any problems with the order or you don&rsquo;t see the required customization or printing features, please let us know at the earliest. You can call us at (886)-472-5540, or you can send us an e-mail at&nbsp;</span><span style=\"color:#4a6ee0\">support@premiumboxes.com</span><span style=\"color:#0e101a\">.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We must be informed within the first three days after the delivery of your order. A refund of money is not the option, but we do offer the option of re-printing if the fault is at our end. This offer is only valid if the company is at fault for the observed issue.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Once you share the issues with us, our team will inspect the order in an efficient manner to know about the potential defects and faults. In addition, the received order must be sent back to us within a total of seven working days if you want any changes. You must also send digital proof (photographs or a short video) of the observed deficiencies and faults. We will go through the order details and accept the mistake if the inconvenience is happened due to our negligence.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">However, if the fault is at the customer&rsquo;s side and they still want a refund, they will have to send us the whole order back within seven working days. The shipping charges and the production costs would be deducted, and the remaining amount will be sent back to the customer as a refund.</span></span></p>', 'Return Policy | How You can Return Your Amount', 'Return Policy, How You can Return Your Amount', 'Return Policy, Premium Boxes Return Policy, How to get my amount back', '16263469981747222766.return-policy.jfif', 'return-policy', 7, 1, 3),
(33, 'FAQ', 'frequently-asked-questions', 'Frequently Asked Questions', '<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">What are your shipping details? Are there any charges?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We offer free delivery within the USA, and your order should arrive within 10-12 business days. However, if you need the order a bit earlier, we also offer an expedited delivery plan. It takes 6 working days to deliver the order to your doorstep, but you will have to pay a minimal amount for delivery charges.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">What type of boxes do you offer?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We offer a large variety of packaging options including rigid boxes, folding boxes, die-cut boxes, and more. We are also open to listening to your demands in this regard, as customers are our top priority. You can select from an extensive range of available customization features.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">Do you offer printing services?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Yes, we also deal in multiple modern printing services. We offer screen-printing, offset printing, and digital printing. We also offer embossed and debossed finishing options.&nbsp;</span><span style=\"color:#4a6ee0\">www.premiumboxes.com</span><span style=\"color:#0e101a\">&nbsp;uses eco-friendly inks, adhesives, and dyes, and has professional staff who are experienced in the printing field to make your experience as smooth as possible.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">Which file formats do you support for submitting the printing design?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">While we prefer .pdf files for convenience and compatibility with all of our tools, we also accept .psd and .jpeg files.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">How can I get an idea about the appearance of the finished product?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">If you want to be sure of the printing design and quality, the finished product will be the same as it appears on your computer screen.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Once your design is completed in your digital workspace, we guarantee that the design of the finished product will appear as exactly as submitted. We believe in full customer satisfaction and are here to help you achieve the results you want. Therefore, we offer 2D and 3D samples at a smaller fee, available at specific requests.</span></span><br />\r\n&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">What are my payment options?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We accept payment through the following options:</span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\">PayPal</span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\">Visa Card</span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\">Master Card</span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\">American Express</span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\">Cheques and wires</span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">I want to buy rigid boxes for my jewelry products. Can you help with projects like this?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Yes, we are offering a wide range of boxes for multiple types of products for our customers. We deal in rigid boxes of the highest quality that can enhance the value of your jewelry items. You can select the size, shape, and customization options as per your requirements. We believe in high-quality products and our goal is to help meet your project needs to your satisfaction.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">What is your price range?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Our prices vary depending on products and customization, but we make sure to offer a selection of affordable options and are willing to work with your budget! You can also sign up for our mailing list, so you can keep an eye out for seasonal promotions and discounts. For more accurate pricing details, contact us at&nbsp;</span><a href=\"mailto:support@premiumboxes.com\" style=\"color:#0563c1; text-decoration:underline\" target=\"_blank\"><strong><span style=\"color:#0e101a\">support@premiumboxes.com</span></strong></a><strong><span style=\"color:#0e101a\">.</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><strong><span style=\"color:#0e101a\">How can I place my order?</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"color:#0e101a\">You just need to sign up at our website and choose your desired products. Add your required items to the cart place the order and follow the instructions for the payment process.</span></span></p>', 'Frequently Asked Questions @  You Can Ask We Will Ans', 'Frequently Asked Questions, If You Have any Question you can let us know, we\'ll try to give the best solution', 'Frequently Asked Questions, Premium Boxes, Print Your Own Boxes, Ask Questions', '1627564145983577866.FAQ.jpg', 'Frequently Asked Questions', 7, 1, 2),
(34, 'Categories', 'categories', 'Categories', NULL, 'Categories', 'Categories', 'Categories', NULL, NULL, NULL, 1, 0),
(35, 'Our Products', 'our-products', 'Our Products', NULL, 'Our Products', 'Our Products', 'Our Products', NULL, NULL, NULL, 1, 0),
(36, 'Track Your Order', 'track-your-order', 'Track Your Order', NULL, 'Track Your Order', 'Track Your Order', 'Track Your Order', NULL, NULL, NULL, 1, 0),
(37, 'Payment  Methods', 'payment-methods', 'Payment  Methods | Payment Procedure', '<h1 style=\"text-align:justify\"><span style=\"color:#0e101a\"><strong>Payment&nbsp; Methods</strong></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">We always make sure that our customers go through secure and reliable payment choices. We generally offer the following options in this regard:&nbsp;</span></span></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">PayPal</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">MasterCard</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Visa Card</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">American Express</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Wires and Cheques</span></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">If you are aware of any of the above options already, you need not worry at all, as you will instantly go through the payment process. You can choose from any one of these options at your convenience.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Please note that all the prices of the products are in USD. Therefore, we only accept payment in the same currency. Besides, you must follow the following instructions when you want to pay for your order:</span></span></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Add items to the cart and go through the list carefully</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Click on the button for order confirmation</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Select the payment method from the mentioned options</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Enter your account details carefully</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Enter the total amount of your order</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Click on the &ldquo;<strong>Send Money</strong>&rdquo; button and answer all the questions asked</span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:#0e101a\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Once we receive the amount, you will get a confirmation message or e-mail from us</span></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Today, people prefer online shopping. Therefore, payments through mobile applications are the current need. We only accept payments that are sent from the options mentioned above. Please read the following guide to have detailed information about the payment processes associated with us.&nbsp;</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Go to the website and look for your desired products. Add items to the cart and go through the whole list carefully. See the final amount and select the payment options per your convenience. Confirm the order and add your account details. Add your contact details too so that we could send the confirmation message or e-mail.&nbsp;</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">As soon as we get the payment, we will send you a confirmation text and move forward with the order processing. We make sure that our payment methods are smooth, secure, and fully reliable, and you can trust us for your money.&nbsp;</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Remember:</span></span></strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">You can only cancel your order within the first four hours after the confirmation. If you intend to cancel your order after this time limit, you will have to pay some amount as the cancellation fee. In normal circumstances, it is usually 10% of the total amount.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Moreover, if there are any changes in the total bill, we will notify you at the earliest. It happens if you want to add more custom options or you want some additional changes in the order.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"color:#0e101a\">Lastly, if the ordered products are no longer available, we will discuss a suitable alternative option with you that sits well with the interests of our customers.</span></span></span></span></p>', 'Payment | Payment Procedure @ PremiumBoxes', 'Payment, Payment Procedure, Complete details about how to order and how to proceed the payment.', 'Payment | Payment Procedure , How to get discount, how to get back your money, PremiumBoxes', '16263500431375110007.Payment  Methods.jpg', 'Payment Procedure', 6, 1, 3),
(38, 'Our Blog', 'our-blog', 'Our Blog', '<p>Our Blog</p>', 'Our Blog', 'Our Blog', 'Our Blog', '', 'Our Blog', 2, 1, 1);

