INSERT INTO `home_faqs` (`id`, `question`, `answer`, `status`, `created_at`, `updated_at`) VALUES
(1, 'What is your minimum order quantity?', 'Our standard minimum order quantity is typically 100 units, but we can accommodate smaller runs depending on the specific box style and material.', 1, '2026-06-30 06:55:48', '2026-06-30 06:55:48'),
(2, 'Can I customize the size and design?', 'Yes! All of our boxes are 100% customizable in terms of size, material, color, and finish to perfectly match your brand.', 1, '2026-06-30 06:55:48', '2026-06-30 06:55:48'),
(3, 'How long does production take?', 'Standard production turnaround is usually 8-12 business days after artwork approval. We also offer expedited shipping if you need your boxes sooner.', 1, '2026-06-30 06:55:48', '2026-06-30 06:55:48'),
(4, 'Do you offer free design support?', 'Absolutely! Our team of packaging experts provides free design assistance to ensure your artwork is print-ready.', 1, '2026-06-30 06:55:48', '2026-06-30 06:55:48'),
(5, 'what is your nam e', 'hassan ahssa', 1, '2026-06-30 06:57:29', '2026-06-30 06:57:29');

