--
-- Table structure for table `home_page_content`
--

CREATE TABLE `home_page_content` (
  `content_id` int(11) NOT NULL,
  `description` longtext NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

--
-- Dumping data for table `home_page_content`
--

INSERT INTO `home_page_content` (`content_id`, `description`) VALUES
(1, '<h1 style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Premium Boxes | Top Packaging Manufacturer in the USA</strong></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Packaging is an essential need for product manufacturing businesses.&nbsp;<strong>Custom boxes&nbsp;</strong>in this regard are providing a wide range of advantages to help out brands. They are customizable in terms of shapes and sizes due to the flexibility that they have. Similarly,&nbsp;<strong>rigid boxes&nbsp;</strong>have the utmost strength and durability. This incredible strength comes with the use of cardboard, corrugated, and bux board materials. Any business can get them printed with important information of product and business values. They show astonishing results to advanced printing methods and technologies. That is the reason why they come with enticing printed themes and layouts. You can easily get them coated or laminated with various finishing techniques to enhance their visual appeal as well as safety.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Every business that sells products has the need to preserve and present its items distinctively. This diversity can only come true by the use of&nbsp;<strong>custom boxes</strong>. They are reliable choices in making the display of valuable items remarkable. These&nbsp;<strong>rigid boxes</strong>&nbsp;protect your items from all kinds of losses that may come in transportation and other handling mediums. However, it is essential that you always consider a perfect source for their purchasing. We are providing the latest and the most efficient qualities of these packaging solutions. Learn the services that make us different from the rest of the market.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:22px\"><span style=\"color:#0e101a\"><strong>Customized Packaging |&nbsp;</strong></span><strong><span style=\"color:#0e101a\">Extremely Affordable Prices:</span></strong></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Sometimes it is hard to create or monitor your budget in a product manufacturing business. You have to deal with the expenses regarding marketing and quality maintaining factors. In this situation, separating a huge portion of the budget to buy&nbsp;<strong>customized packaging&nbsp;</strong>is a little hard. We, in this regard, are helping our beloved customers by taking care of their packaging needs without giving them higher rates. All over the year, we propose different sales, discounts, and seasonal deals. Our wholesale prices are also very economical that will encourage you to get your product packaging in bulk amounts. However, our main goal is just to make things easier for our customers. We do not make any compromise on the quality of the packages.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><strong><span style=\"color:#0e101a\">Advanced Custom Printing Options | Print Your Own Packaging:</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">It is a myth that packaging is just for the holding and preserving of items. It can play a great role in attracting a huge customer base and promoting brand values. For that, all you need is to get them printed with quality materials and advanced methods. We provide&nbsp;<strong>custom printed boxes&nbsp;</strong>and give our customers the liberty to choose printing type according to their requirements. We provide the given printing options to our valuable customers;</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">&middot;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>Digital printing:</strong>&nbsp;It is an advanced printing process that utilizes direct ink-spreading methods to the sheet. It works with both CMYK and PMS color pallets to get desirable printed patterns.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">&middot;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>Offset printing:&nbsp;</strong>It is a method that gives mass printing options for product packaging. The initial setup of this process is not that complex, which explains its low price.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">&middot;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>Screen printing:&nbsp;</strong>The screen printing method is the only one in which you do not have to worry about printing every side of the box separately. It has plates on which you can roll your color scheme and add them to your paper layers.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">We provide the finest qualities of all of these methods to make sure that our customers get desirable printing results.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><strong><span style=\"color:#0e101a\">Product Safety is Our Priority:</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Every brand has this need to preserve its valuable items safely for a long time. Customers usually rely on the manufacturers when it comes to secure deliveries or shipments of the products. For that, if you are not capable of getting durable&nbsp;<strong>rigid boxes</strong>&nbsp;for your items, you might lose the trust of your customers. We do not want our customers to face these kinds of losses. We use durable and sturdy materials to manufacture the packaging. These materials include kraft, cardboard, and corrugated sheets. We use the finest qualities of these materials to make sure that you get reliable solutions for the protection of your items.</span>&nbsp;</span><br />\r\n<br />\r\n<span style=\"font-size:18px\"><strong><span style=\"color:#0e101a\">Latest Finishing Options:</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">Enhancement of&nbsp;<strong>custom packaging&nbsp;</strong>can take your items to the considerations of your target audience. For that, there are finishing methods that you can ask for your product boxes. We offer the latest and quality finishing options that will increase the worth of your product packaging. You can get your&nbsp;<strong>premium boxes&nbsp;</strong>coated and laminated with matte, gloss, spot UV, soft-touch, and smudge-free lamination from us. We also provide foiling solutions like gold and silver. To enhance the printing on the boxes, you can also ask us for options such as embossing and debossing. We provide all of these options according to your packaging requirements without taking a lot of your budget.</span></span><span style=\"font-size:12pt\">&nbsp;</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:18px\"><strong><span style=\"color:#0e101a\">Free of Cost Shipping:</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">For many customers, the main reason to ignore online purchasing is the extensive shipping cost. There are different names in the packaging sector that are using the shipping cost to get back the discounts on&nbsp;<strong>luxury boxes</strong>. However, you can get your product packaging with free of cost shipping at&nbsp;</span><u><strong><span style=\"color:#4a6ee0\">www.premiumboxes.com</span></strong></u><span style=\"color:#0e101a\">&nbsp;in every part of the United States of America. However, we do not forget about our international customers as well. Our shipping charges for international customers are extremely low that they are hardly noticeable. Plus, we only deliver&nbsp;<strong>luxury packaging&nbsp;</strong>in just 10 to 12 working days after the order confirmation. Also, we offer a rush delivery option. You can chat with our representatives if you want to avail of this service. We entertain rush deliveries in just 6 business days after the final approval.</span></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"color:#000000\"><strong><span style=\"font-size:18px\">Custom Boxes | Print Your Own Packaging</span></strong></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"color:#0e101a\">These are not the days when you can make compromises on the quality and presentation of your items and still get better sales. Customers are cautious, and they always prefer quality. That is why we are offering the finest quality of the&nbsp;<strong>custom boxes.</strong>&nbsp;With our affordable prices and remarkable services, you can get numerous advantages regarding the promotion of your business. Our only goal is to provide you with the boxes that can help you in achieving success and stability for your brand.</span></span></p>');

