(199, 'Chinese Takeout Boxes', 'chinese-takeout-boxes', 'Chinese Takeout Boxes', 'Chinese Takeout Boxes', 'Chinese Takeout Boxes', '<p>Chinese Takeout Boxes</p>', '<p>Chinese Takeout Boxes</p>', 'chinese-takeout-boxes.jpg', 'Chinese Takeout Boxes', '[\"chinese-takeout-boxes.jpg\",\"custom-chinese-takeout-boxes.jpg\",\"customized-chinese-takeout-boxes.jpg\",\"printed-chinese-takeout-boxes.jpg\"]', 81, '[\"180\",\"184\",\"186\",\"191\"]', 1, 0),
(200, 'Chinese Food Boxes', 'chinese-food-boxes', 'Chinese Food Boxes', 'Chinese Food Boxes', 'Chinese Food Boxes', '<p>Chinese Food Boxes</p>', '<p>Chinese Food Boxes</p>', 'chinese-takeout-boxes.jpg', 'Chinese Food Boxes', '[\"chinese-takeout-boxes.jpg\",\"custom-chinese-takeout-boxes.jpg\",\"customized-chinese-takeout-boxes.jpg\",\"printed-chinese-takeout-boxes.jpg\"]', 81, '[\"181\",\"182\",\"183\",\"184\"]', 1, 0),
(201, 'Display Boxes', 'display-boxes', 'Display packaging is considered the backbone of retail businesses. PremiumBoxes offers it with free of cost shipping and design support.', 'Display Boxes, Display Packaging, Premium Boxes, custom display packaging', 'Display Boxes | Display Packaging, Premium Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">The retail business market depends on the display of the products, and no other packaging can perform the job better than the display packaging. It presents and protects the products simultaneously. Various customization options such as the choice of shape, size, style, and thickness of the manufacturing material are offered. This packaging is printed using the latest printing techniques along with organic inks and dyes. Quick turnaround along with free shipping is available for these packaging solutions. PremiumBoxes offers the most intriguing yet economical <em><strong>display packaging supplies</strong></em> in the United States of America.</span></p>', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Perfect Printing</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use the latest techniques to get the perfect results for the printing of&nbsp;<strong>display boxes</strong>. CMYK and PMS color schemes are used. All the inks and dyes used in the process of printing are 100 percent organic.</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Customizations at Their Best</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers the best customization options for these&nbsp;<strong>custom display packaging</strong>&nbsp;solutions. The clients can choose the size, style, design, and shape of these boxes. They are available in single panel, double panel, and multi-panel shapes. Custom inserts, placeholders, and handles can also be added to these boxes.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer professional design assistance to our clients with zero charges. A 2D or 3D template of the design is also provided to the clients.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Get Free Delivery</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free doorstep delivery of these boxes for clients across North America. Shipping for international clients is also available on demand.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Enjoy Discounted Pricing</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes strives to offer the lowest prices for display packaging to facilitate the clients. Volume discounts for larger orders are also available.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Get connected to our customer care professionals via dedicated chat portal, e-mail, or call to get more information. A call-back request is also an option to reach us.</span></p>', 'custom-printed-display-boxes.jpg', 'Display Boxes', '[\"cardboard-display-boxes.jpg\",\"custom-display-boxes.jpg\",\"custom-printed-display-boxes.jpg\",\"display-boxes.jpg\"]', 80, 'null', 1, 0),
(202, 'Counter Display Boxes', 'counter-display-boxes', 'Counter display boxes are beneficial for businesses to showcase their products on counters. PremiumBoxes provides various add-ons along with free shipping for them.', 'Counter Display Boxes, Cardboard Counter Display Boxes, Counter Display Packaging', 'Counter Display Boxes | Cardboard Counter Display Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Counter display boxes are used to present the products. PremiumBoxes manufactures this packaging with 100% organic materials such as corrugated, cardboard, and Kraft stocks. Various techniques are used to print these boxes. Clients can get them with different add-ons such as inserts, trays, holders, and dividers. Their shapes, styles, and sizes are customizable. Finishing options including smudge-free, foiling, glossy, soft-touch, and many more are available for these boxes. Different printing techniques, including screen, digital, and offset, are used for the printing of these boxes. Free design support and free shipping across North America are also available for these boxes.</span></p>', '<p><span style=\"color:#000000\"><strong>Counter display boxes&nbsp;</strong>are an essential need of retail brands. PremiumBoxes offers these packages with many features.&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Essential Add-ons</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">We offer different add-ons for display packaging that include inserts, dividers, trays, and holders to improve their showcasing abilities.&nbsp;</span></p>\r\n\r\n<h1><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Enjoy Budget-Friendly Prices</strong></span></span></h1>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes offers this packaging at budget-friendly prices. Clients can enjoy special discounts on large quantities.&nbsp;</span></p>\r\n\r\n<h2><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Customizable Packaging Solution</strong></span></span></h2>\r\n\r\n<p><span style=\"color:#000000\">We provide&nbsp;<strong>custom counter display boxes&nbsp;</strong>with the options to customize their shapes, designs, and sizes.&nbsp;</span></p>\r\n\r\n<h3><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Sustainable Materials</strong></span></span></h3>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes uses sustainable materials such as Kraft, corrugated, and cardboard stocks for the manufacturing of these boxes.&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>The Latest Printing Techniques</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">We use the latest printing techniques along with PMS and CMYK color schemes to print these packaging solutions.&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Some Additional Free Services</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes provides many additional services without any charges. These services are as follows:</span></p>\r\n\r\n<ul>\r\n	<li><span style=\"color:#000000\">Complimentary design support</span></li>\r\n	<li><span style=\"color:#000000\">Free shipping across the United States of America and Canada</span></li>\r\n	<li><span style=\"color:#000000\">No die-cut or plate charges</span></li>\r\n</ul>', 'display-boxes.jpg', 'Counter Display Boxes', '[\"cardboard-counter-display-boxes.jpg\",\"counter-display-boxes-cardboard.jpg\",\"display-boxes.jpg\",\"printed-display-boxes.jpg\"]', 80, '[\"201\",\"203\",\"222\",\"464\"]', 1, 0),
(203, 'Cosmetic Display Boxes', 'cosmetic-display-boxes', 'Cosmetic Display Boxes', 'Cosmetic Display Boxes', 'Cosmetic Display Boxes', '<p>Cosmetic Display Boxes</p>', '<p>Cosmetic Display Boxes</p>', 'cosmetic-display-boxes.jpg', 'Cosmetic Display Boxes', '[\"cosmetic-display-boxes.jpg\",\"customized-display-boxes.jpg\",\"display-boxes-wholesale.jpg\",\"printed-cosmetic-boxes.jpg\"]', 80, '[\"202\",\"203\",\"254\"]', 1, 1),
(204, 'Gold Foil Boxes', 'gold-foil-boxes', 'Gold foil boxes are essential for adding value to the products. PremiumBoxes uses organic materials to manufacture these boxes. Free shipping across the USA is available.', 'Gold Foil Boxes, Foil Packaging, Foil boxes, Shin Packaging, Foiling on Packaging, Gold Foiling Sheet', 'Gold Foil Boxes | High Quality Foiling on Packaging', '<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Gold foil boxes&nbsp;</strong>are among the most luxurious packaging solutions. PremiumBoxes offers this packaging with various customizations. Eco-friendly materials are used for the manufacturing of these boxes. Metallic gold foil is used for the finishing of this packaging. There are other finishing options, such as embossing and debossing, that can be used for these boxes. The option to add die-cut windows, holders, inserts, and dividers in these boxes is also available. Latest printing techniques are used to print them. These boxes are shipped to the clients in ready to assemble flat shape.</span></p>', '<p><span style=\"color:#000000\"><strong>Gold foil boxes&nbsp;</strong>are the need of every high-class brand these days. PremiumBoxes uses various customizations to personalize the shapes and styles of these boxes.&nbsp;</span></p>\r\n\r\n<h1><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Vivid Printing Techniques</strong></span></span></h1>\r\n\r\n<p><span style=\"color:#000000\">We use different printing techniques such as digital, silkscreen, and offset to print this packaging. Free design support, along with the choice of color schemes, is also available.&nbsp;</span></p>\r\n\r\n<h2><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></h2>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes provides free shipping across the USA and Canada. Shipping for international clients is also available on demand.&nbsp;</span></p>\r\n\r\n<h3><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Essential add-ons</strong></span></span></h3>\r\n\r\n<p><span style=\"color:#000000\">Essential add-ons such as holders, dividers, inserts, and die-cut windows are available for these boxes.&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Exceptional Customer Service</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">The professional team of PremiumBoxes assists the clients at every stage. Clients can contact us through an online chat portal, email, and call.&nbsp;</span></p>\r\n\r\n<h3><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Sustainable Materials</strong></span></span></h3>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes uses 100% organic materials such as cardboard, Kraft, and corrugated stocks to manufacture these boxes. Also, the inks, dyes, and adhesives used for these boxes are 100 percent organic and biodegradable.</span></p>', 'gold-foil-boxes.jpg', 'Gold Foil Boxes', '[\"custom-gold-foil-boxes.jpg\",\"gold-foil-box.jpg\",\"gold-foil-boxes.jpg\",\"gold-foil-boxes-wholesale.jpg\"]', 79, '[\"201\",\"202\",\"203\",\"205\"]', 1, 0);
