(210, 'Ornament Boxes', 'ornament-boxes', 'Ornament Boxes', 'Ornament Boxes', 'Ornament Boxes', '<p>Ornament Boxes</p>', '<p>Ornament Boxes</p>', 'ornament-boxes.jpg', 'Ornament Boxes', '[\"cardboard-ornament-boxes.jpg\",\"customized-ornament-boxes.jpg\",\"custom-printed-ornament-boxes.jpg\",\"ornament-boxes.jpg\"]', 64, '[\"150\",\"153\",\"206\",\"207\"]', 1, 0),
(211, 'Archive Boxes', 'archive-boxes', 'Archive boxes are the best solutions for organizing documents at the workplace. PremiumBoxes manufactures these boxes with eco-friendly materials.', 'Archive Boxes', 'Archive Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Every organization needs archive boxes for multiple purposes. PremiumBoxes offers these boxes at the most affordable prices. Fascinating finishing options are available for these boxes. Modern printing techniques are used to print these boxes. Customizations in style, shape, and design, along with the choice of adding holders and dividers, are available. The option of adding a die-cut window is also available. These boxes are available with free shipping and complimentary design support.</span></p>', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Nature-friendly Materials</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Biodegradable and recyclable materials such as corrugated and cardboard stocks are used to manufacture these boxes. Sustainable inks are used for the printing of these boxes.&nbsp;</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Affordable Packaging Solutions</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes provides these packaging solutions at the most economical pricing. Volume discounts are also available. We use secure payment channels for transactions.&nbsp;</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Fascinating Finishing Techniques</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Latest finishing options, including smudge-free, gloss, soft-touch, matte, watermark, and many more, are available for these boxes.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Doorstep Delivery</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes provides free doorstep delivery across the USA and Canada. The option of rush delivery is also available on demand.&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Essential add-ons</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Add-ons such as holders and dividers are available for various types of&nbsp;<strong>archive storage boxes.</strong>&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Remarkable Customizations</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">End-to-end customization options are available for these&nbsp;<strong>archive boxes.&nbsp;</strong>PremiumBoxes offers the best customizations, including the choice of shape and size of these boxes.</span></p>', 'customized-archive-boxes.jpg', 'Archive Boxes', '[\"archive-boxes.jpg\",\"cardboard-archive-boxes.jpg\",\"custom-archive-boxes.jpg\",\"customized-archive-boxes.jpg\"]', 67, '[\"215\",\"221\",\"223\",\"242\"]', 1, 0),
(212, 'Book Boxes', 'book-boxes', 'Book boxes are one of the finest packaging solutions. They are used for multiple purposes. PremiumBoxes provides them at affordable pricing and free shipping.', 'Book Boxes', 'Book Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Book boxes are among the most elegant and protective packaging solutions. They are used for different purposes at domestic as well as professional levels. They can carry different types of items without hassle. PremiumBoxes offers amazing customizations for these boxes, including the choice of style, color scheme, design, size, and manufacturing material. The manufacturing materials, as well as the inks used for their printing, are 100 percent organic and safe for the natural environment. Also, the clients can enjoy volume discounts for larger orders along with free shipping and free design support.</span></p>', '<p style=\"text-align:justify\"><span style=\"color:#000000\">The custom book boxes are commonly used for keeping valuable items as well as important documents safe. PremiumBoxes is among the top suppliers of custom book packaging in the USA.</span></p>\r\n\r\n<h1 style=\"text-align:justify\"><strong><span style=\"font-size:20px\"><span style=\"color:#000000\">Top-Quality Printing</span></span></strong></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use the latest printing techniques, including digital, offset, and screen printing, for custom book boxes. The clients can choose the type of printing as well as the design for these boxes. Also, PMS and CMYK color palettes are used in the printing processes.</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><strong><span style=\"font-size:18px\"><span style=\"color:#000000\">Free Design Support</span></span></strong></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We provide free-of-cost design support to the clients. Making of a whole new design as well as making changes in a standard design as per the clients&rsquo; needs are available. A 2D or 3D sample of the design is also provided on demand.</span></p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Free Shipping Across North America</span></span></strong></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free-of-cost shipping of book boxes across the United States of America and Canada. Shipping for international clients is also available on request.</span></p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Go Green</span></span></strong></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">At PremiumBoxes, we use only organic and eco-friendly supplies for the manufacturing and printing of these boxes. The supplies that we use include cardboard stock, kraft stock, corrugated stock, and paper stock. The clients can choose the material as per their preferences or seek our professional assistance in this regard as well.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We are available to the customers at the earliest via call, dedicated chat portal, and e-mail. A call-back request is also an option to reach us.</span></p>', 'cardboard-book-boxes.jpg', 'Book Boxes', '[\"book-boxes.jpg\",\"cardboard-book-boxes.jpg\",\"custom-book-boxes.jpg\",\"custom-printed-book-boxes.jpg\"]', 67, '[\"153\",\"223\",\"225\",\"227\"]', 1, 0),
(214, 'Candle Boxes', 'candle-boxes', 'Candle Boxes', 'Candle Boxes', 'Candle Boxes', '<p>Candle Boxes</p>', '<p>Candle Boxes</p>', 'custom-candle-boxes.jpg', 'Candle Boxes', '[\"candle-boxes.jpg\",\"candle-boxes-wholesale.jpg\",\"custom-candle-boxes.jpg\",\"custom-printed-candle-boxes.jpg\"]', 67, '[\"218\",\"219\",\"221\",\"230\"]', 1, 1),
(215, 'Printed Cardboard Boxes', 'printed-cardboard-boxes', 'Printed cardboard boxes are the most adaptable and versatile packaging solutions. PremiumBoxes offers them at affordable pricing along with free shipping.', 'Printed Cardboard Boxes', 'Printed Cardboard Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Printed cardboard boxes are used in every business industry across the globe. They are the best to make the products prominent in the retail market. These boxes are made with organic cardboard stock. The inks used in their printing are also organic. PremiumBoxes provides these boxes with a number of customization options, including the choice of size, shape, design, style, and color scheme. Other customization options such as the addition of a die-cut window, inserts, handles, and placeholders are also available. Free shipping and complimentary design support are offered for these boxes.</span></p>', '<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><strong>Enjoy the Lowest Pricing</strong></span></h1>\r\n\r\n<p style=\"text-align:justify\">PremiumBoxes strives to provide clients with the finest&nbsp;<strong>cardboard boxes</strong>&nbsp;at the lowest possible prices. We offer special discounts on larger orders of&nbsp;<strong>cardboard packaging</strong>. Also, all the transactions are made through secure and trusted channels only.&nbsp;</p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><strong>Get the Finest Printing</strong></span></h2>\r\n\r\n<p style=\"text-align:justify\">We use the latest printing technologies along with PMS and CMYK color palettes for&nbsp;<strong>custom printed cardboard boxes</strong>. The clients can get customized designs printed with the best results. Also, we offer free-of-cost design support to the clients for these&nbsp;<strong>printed cardboard boxes</strong>. A 2D or 3D mockup of the final design can also be provided to the clients on demand.&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><strong>Customizations at their best</strong></span></p>\r\n\r\n<p style=\"text-align:justify\">PremiumBoxes offers the best customization options for&nbsp;<strong>custom cardboard boxes</strong>. The size, style, shape, and color scheme of these boxes are customizable, following the clients&rsquo; needs. Also, there are no die-cut or plate charges applied for these boxes.&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><strong>Get free shipping</strong></span></p>\r\n\r\n<p style=\"text-align:justify\">PremiumBoxes offers free of cost delivery of&nbsp;<strong>custom cardboard packaging</strong>&nbsp;solutions across the United States of America and Canada. Rush delivery option is also available on demand. Shipping for international clients is also available.&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><strong>Get connected now!</strong></span></p>\r\n\r\n<p style=\"text-align:justify\">PremiumBoxes is available to assist the clients at the earliest via dedicated chat portal, e-mail, and call.</p>', 'cardboard-boxes.jpg', 'Printed Cardboard Boxes', '[\"cardboard-boxes.jpg\",\"Custom-cardboard-boxes.jpg\",\"custom-printed-cardboard-box.jpg\",\"custom-printed-cardboard-boxes.jpg\"]', 67, '[\"217\",\"220\",\"223\",\"230\"]', 1, 0),
(216, 'CD/DVD Storage Boxes', 'cd-dvd-storage-boxes', 'CD/DVD storage boxes are commonly used at commercial as well as domestic levels. PremiumBoxes offers amazing customization options and free shipping for these boxes.', 'CD/DVD Storage Boxes', 'CD/DVD Storage Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">CD/DVD storage boxes are the need of everyone. They are designed to protect fragile disks from dust, moisture, and bumps. PremiumBoxes offers a number of customization options for these boxes. These options include the choice of size, shape, style, design, manufacturing material, and its thickness. Also, the customers can choose the number of inserts or handles to be added to these boxes. Commonly used materials for these boxes include cardboard, kraft, and corrugated stocks. Volume discounts, free shipping, and complimentary design support are also available for these boxes.</span></p>', '<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes is among the top CD/DVD storage boxes suppliers in the United States of America. We offer these boxes with exclusive features and discounts.</span></p>\r\n\r\n<h1 style=\"text-align:justify\"><strong><span style=\"font-size:20px\"><span style=\"color:#000000\">Complimentary Design Support</span></span></strong></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer complimentary design support to the clients for these boxes. Making a new design from scratch and making changes in an existing design are offered in design support. A 2D or 3D mockup of the design is also provided on demand.</span></p>\r\n\r\n<h2 style=\"text-align:justify\"><strong><span style=\"font-size:18px\"><span style=\"color:#000000\">End to End Customization</span></span></strong></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">At PremiumBoxes, we offer end-to-end customization options to clients. The clients can choose the manufacturing material and its thickness as well as the size, style, shape, and design of the packaging solutions as per their preferences.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Superior Printing</span></span></strong></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We provide the finest printing of these CD storage boxes using the latest printing techniques along with CMYK and PMS color palettes. Also, we use only organic inks for the printing of these boxes.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Alluring Finishing</span></span></strong></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers various finishing styles for these DVD storage boxes. The clients can choose from matte, gloss, spot UV, soft-touch, smudge-free, and foil stamping options.</span></p>\r\n\r\n<h3 style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Free Delivery</span></span></strong></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers free-of-cost doorstep delivery of these boxes across the United States of America and Canada. International clients can also avail of shipping on demand.</span></p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"font-size:16px\"><span style=\"color:#000000\">Get Connected Now!</span></span></strong></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes provides seamless customer support at every step for CD/DVD storage boxes. Dedicated chat support, call, e-mail, and a call-back request are the ways to get connected with us.</span></p>', 'cd-storage-boxes.jpg', 'CD/DVD Storage Boxes', '[\"cd-storage-boxes.jpg\",\"custom-cd-storage-boxes.jpg\",\"customized-cd-storage-boxes.jpg\",\"dvd-storage-boxes.jpg\"]', 67, '[\"161\",\"218\",\"223\",\"226\"]', 1, 0),
