INSERT INTO `product` (`product_id`, `title`, `url`, `meta_description`, `meta_tags`, `meta_title`, `description`, `long_description`, `image`, `altname`, `images`, `cat_id`, `related_product`, `status`, `show_home`) VALUES
(299, 'Luxury Boutique', 'luxury-boutique', 'PremiumBoxes offers many attractive designs of luxury boutique. They are available in all sizes. Get these boxes at the lowest prices.', 'Luxury Boutique, Custom Boutique Boxes, Luxury Boutique Packaging , Boutique Packaging', 'Custom Boutique Boxes | Luxury Boutique Packaging', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Different eye-catching designs of&nbsp;<strong>luxury boutique</strong>&nbsp;boxes are available. They are customizable in any size, shape, color, or style according to clients&rsquo; needs. Their manufacturing materials are eco-friendly and sustainable bux board, kraft, or cardboard. Their thickness is customizable according to clients&rsquo; needs. Different features such as inserts, placeholders, or compartments can be added on request. They also come with printed graphics, logos, and the name of the brand. Many additional features are also available for increasing their visual appeal. Free shipping and free design support are also available under certain conditions.</span></p>', '<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Luxury boutique</strong>&nbsp;boxes come in attractive and distinctive shapes and styles. PremiumBoxes offers various services and features for these boxes.<strong>&nbsp;</strong></span></p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Biodegradable Materials</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We utilize environmentally friendly materials for manufacturing&nbsp;<strong>clothing packaging bags</strong>. These materials include kraft, bux board, and cardboard stock. These materials are available in variable thicknesses. The inks and adhesives used for these boxes are also eco-friendly.<strong>&nbsp;</strong></span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Customized Features</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers&nbsp;<strong>clothing packaging boxes</strong>&nbsp;with multiple customized features. Clients can get them in all desired shapes, sizes, colors, and styles. Die-cut windows, custom inserts, placeholders, and compartments are added on request. Many finishing options such as coatings, foiling, embossing, stamp foiling, and others are also available.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Sustainable and low-cost Packaging</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer&nbsp;<strong>custom clothing packaging boxes at the lowest prices</strong>. Also, we offer special discounts for large volume orders. All payments are made through trusted and secured channels.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes is offering free shipping for clients across the USA and Canada. Rush delivery is also available under certain terms. Shipping is also available for international clients on request.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">Free design support is available for clients to get astonishing&nbsp;<strong>personalized clothing packaging.</strong><strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>High-quality Printing</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use high-quality printing along with PMS and CMYK color schemes. We offer impressive quality printing by using offset, screen, and digital technologies.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Customer Care Service</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">A dedicated and professional team is always available for assistance. Contact us through email, live chat, and call.</span></p>', 'clothing-packaging-boxes-luxury.jpg', 'Luxury Boutique', '[\"clothing-packaging-boxes.jpg\",\"clothing-packaging-boxes-luxury.jpg\",\"custom-clothing-packaging-boxes.jpg\",\"luxury-packaging-boutique.jpg\"]', 85, '[\"300\",\"301\",\"302\"]', 1, 0),
(300, 'Luxury Lingerie Boxes', 'luxury-lingerie-boxes', 'There are many attractive designs of luxury lingerie boxes at PremiumBoxes. Get a variety of elegant designs of these boxes at the most affordable prices.', 'Luxury Lingerie Boxes, Lingerie Boxes, Pink Lingerie Boxes, white Luxury Lingerie Boxes', 'Pink and white Luxury Lingerie Boxes | PremiumBoxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Numerous astonishing shapes and colors of&nbsp;<strong>luxury lingerie boxes</strong>&nbsp;are available at PremiumBoxes. These boxes keep the items safe and also improve brand recognition. Their manufacturing materials are kraft, bux board, and cardboard stocks. Many customization options are available to enhance the attractiveness of these boxes. Clients can choose from various finishing options, including coatings, stamp foiling, embossing, PVC, or other add-ons to make them elegant. Modern printing technologies are used to ensure high-quality printing. Die-cut windows, customized lids, and handles are added on demand. Different complimentary services are available for these boxes.</span></p>', '<p><span style=\"color:#000000\"><strong>Luxury lingerie boxes</strong>&nbsp;are essential for attracting customers and presenting lingerie items in the retail market. PremiumBoxes is among the popular packaging suppliers for lingerie in the USA.<strong>&nbsp;</strong></span></p>\r\n\r\n<h1><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Cost-effective Boxes</strong></span></span></h1>\r\n\r\n<p><span style=\"color:#000000\">We strive hard to make these boxes affordable for everyone. We also offer special discounts on large volume orders.<strong>&nbsp;</strong></span></p>\r\n\r\n<h2><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Eco-friendly Materials</strong></span></span></h2>\r\n\r\n<p><span style=\"color:#000000\">We use eco-friendly materials for these boxes. These materials are decomposable and recyclable. The inks and adhesives used for these boxes are also environmentally friendly.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></h3>\r\n\r\n<p><span style=\"color:#000000\">We offer free shipping across North America. Shipping for international clients is also available under certain conditions from other countries. The facility of rush delivery is also available on demand.<strong>&nbsp;</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Design Support</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes provides clients with free design support. Get this service for improving the packaging designs without extra charges.<strong>&nbsp;</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Multiple Options for Customization</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">Many striking shapes and colors of this packaging<strong>&nbsp;</strong>are available. Many additional features such as custom inserts, placeholders, or die-cut windows can be added on demand. We also offer many appealing finishing options such as coatings, foiling, embossing, or PVC.<strong>&nbsp;</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Impressive Printing Quality</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">PremiumBoxes offers to print using the latest technologies. We use digital, offset, and screen printing along with CMYK and PMS color schemes.<strong>&nbsp;</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Customer Support</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\">A professional customer care team is always available for assistance. Contact us through email, live chat, or call.</span></p>', 'luxury-lingerie-boxes.jpg', 'Luxury Lingerie Boxes', '[\"etail-gift-packaging-for-lingerie.jpg\",\"lingerie-packaging.jpg\",\"luxury-lingerie-boxes.jpg\",\"luxury-lingerie-packaging.jpg\"]', 85, '[\"299\",\"301\",\"302\"]', 1, 0),
(301, 'Luxury Textile Boxes', 'luxury-textile-boxes', 'Numerous designs of luxury textile boxes are available in the market. PremiumBoxes is manufacturing these boxes from organic and sustainable materials.', 'Luxury Textile Boxes, Custom luxury Textile Boxes, Textile storage boxes, Textile Packaging, PremiumBoxes', 'Textile storage boxes | PremiumBoxes  - Custom luxury Textile Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Luxury textile boxes</strong>&nbsp;are available in many astonishing shapes and colors. They come in many desired sizes, shapes, and styles. Their manufacturing materials are environmentally friendly. They include kraft, bux board, and cardboard stocks. These materials are available in variable thicknesses. These boxes can also come with die-cut windows, internal inserts, compartments, or placeholders on request. PremiumBoxes uses the latest technologies such as digital, offset, and screen for their printing. Shipping across North America is free under certain conditions. Free design support is also available.</span></p>', '<p style=\"text-align:justify\"><span style=\"color:#000000\"><strong>Luxury textile boxes</strong>&nbsp;are essential for presenting different types of fabrics elegantly. PremiumBoxes is one of the major suppliers of these boxes in the USA.<strong>&nbsp;</strong></span></p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Variety of Customization Options</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">This packaging comes in a variety of shapes, colors, styles, and sizes. It also comes with multiple additional internal features such as inserts, compartments, placeholders, die-cut windows, and handles that can be added on request. Numerous finishing options are also available.<strong>&nbsp;</strong></span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Affordable Materials</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes provides&nbsp;<strong>luxury textile packaging</strong>&nbsp;at the most affordable prices. We offer discounts for large volume orders.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Sturdy and Biodegradable Packaging</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We use production materials that include kraft, cardboard, or bux board stocks. These materials are recyclable and biodegradable. All other supplies for their manufacturing, such as inks and adhesives, are also eco-friendly.<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Design Support Without Extra Charges</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers design support without extra charges. Clients can get this service for the production of astonishing designs of&nbsp;<strong>luxury clothing packaging</strong>.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>No Shipping Charges</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer free shipping across North America. The facility of rush delivery is also available on demand.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>The Best Quality Printing</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We offer high-quality printing at reasonable prices. We offer printing with CMYK and PMS color schemes.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Customer Care Service</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers impeccable customer care service. Contact us for assistance through call, email, or live chat.</span></p>', 'luxury-textile-boxes.jpg', 'Luxury Textile Boxes', '[\"custom-bow-tie-boxes.jpg\",\"fabric-packaging.jpg\",\"luxury-textile-boxes.jpg\",\"luxury-textile-packaging.jpg\"]', 85, '[\"289\",\"299\",\"300\",\"302\"]', 1, 0),
(302, 'Rigid Tie Boxes', 'rigid-tie-boxes', 'Rigid tie boxes are sturdy and durable. They are available in beautiful designs and styles. PremiumBoxes is supplying these boxes at the lowest prices.', 'Rigid Tie Boxes,  Bow Tie Packaging,  Bow Tie Boxes, Rigid Tie Boxes, Tie Packaging', 'Rigid Tie Boxes | Custom Bow Tie Packaging and Boxes', '<p style=\"text-align:justify\"><span style=\"color:#000000\">There are many beautiful designs and styles of&nbsp;<strong>rigid tie boxes</strong> available at PremiumBoxes. They are customizable according to clients&rsquo; needs. They come in many desired sizes or colors. They are made of kraft, cardboard, or bux board stocks. These materials are available in variable thicknesses. They are biodegradable and recyclable. These boxes are affordable for all businesses. Inserts, compartments, placeholders, die-cut windows, and handles can also be added on demand. High-quality printing is used to make them more appealing.&nbsp;</span></p>', '<p style=\"text-align:justify\"><span style=\"color:#000000\">Ties look good when present inside beautiful and stylish&nbsp;<strong>rigid tie boxes</strong>. PremiumBoxes is manufacturing these boxes from low-cost and sturdier materials.<strong>&nbsp;</strong></span></p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:20px\"><span style=\"color:#000000\"><strong>Desired Customization&nbsp;</strong></span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We manufacture&nbsp;<strong>tie box packaging</strong>&nbsp;in any size, color, shape, and style. Die-cut windows and handles, placeholders, or custom inserts are added on demand. We also offer multiple finishing options such as embossing, foiling, coatings, and others. Clients can ask for any type of finishing.<strong>&nbsp;</strong></span></p>\r\n\r\n<h2 style=\"text-align:justify\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong>Low-cost Materials&nbsp;</strong></span></span></h2>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes utilizes low-cost materials for making&nbsp;<strong>this packaging</strong>&nbsp;affordable for everyone. All the payments are made through trusted and secured channels.&nbsp;<strong>&nbsp;</strong></span></p>\r\n\r\n<h3 style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Environmentally Friendly Packaging</strong></span></span></h3>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We make use of biodegradable and recyclable materials. All the inks and adhesives used for these boxes are also eco-friendly.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Free Shipping</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes offers the facility of free shipping across North America. Shipping for international clients and rush delivery is also available under certain terms.<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>No Charges For Design Support</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">We provide complimentary design support. Clients can get this service for getting a stunning design of&nbsp;<strong>this packaging</strong>.</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>High-quality Printing</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">PremiumBoxes is offering printing by using the latest technologies. Our<strong>&nbsp;packaging&nbsp;</strong>comes with printed HD graphics, textual details, and other content. We make use of CMYK and PMS color schemes.&nbsp;<strong>&nbsp;</strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>A Professional Customer Care Team</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#000000\">A highly dedicated customer care team is available for assistance. Contact us for assistance through email, live chat, or call.</span></p>', 'tie-box-packaging.jpg', 'Rigid Tie Boxes', '[\"empty-tie-box.jpg\",\"tie-boxes-wholesale.jpg\",\"tie-box-packaging.jpg\",\"tie-sleeve-packaging.jpg\"]', 85, '[\"287\",\"299\",\"300\",\"301\"]', 1, 0),
