INSERT INTO `return_page` (`rp_id`, `meta_title`, `meta_description`, `meta_tags`, `image`, `description`) VALUES
(1, 'return page', 'return page', 'return page', 'return-refund-policy.jpg', '<h1 style=\"text-align:justify\">Pro Custom Boxes Return &amp; Refund Policy</h1>\r\n\r\n<p style=\"text-align:justify\">pro custom boxes is specialized in careful manufacturing as well as designing of product exactly according to client&#39;s requirement. Analyzing details with digital proof is the crucial part for the sales process. We are focused to get your order confirmation before making payments and start manufacturing. Your order sent to design as well as manufacturing department for&nbsp;<strong>manual verifications</strong>. Your approval after analyzing the digital view in 2d and 3D is an essential part of sales. Therefore, we are not accountable for any designing errors that include data, color, misspelling, and other variations.</p>\r\n\r\n<p style=\"text-align:justify\">Once the manufacturing has started, the customer is liable to pay order charged including taxes and shipment charges. Refund with minimum&nbsp;<strong>cancellation fee of 25%</strong>&nbsp;is being applied only if we are unable to full fill our commitment.</p>\r\n\r\n<p style=\"text-align:justify\">It the product does not meet the commitment or found defected, the client is accountable to update the company within 3 business days after delivery confirmation. You are also liable to send the product back to the company<strong>&nbsp;within 7 business days</strong>&nbsp;using your own shipping expenses. The extra charges of rush delivery services are non-refundable.</p>\r\n\r\n<p style=\"text-align:justify\">If shipment got damaged due to unfavorable weather condition or any other external factor, the company will take responsibility for that. If the client has canceled the design service order, the company will charge cancellation fee separately. No compensation is granted for designing services.</p>\r\n\r\n<p style=\"text-align:justify\">If you are facing any problem, make it sure to register your complaint within 3 days of receipt of confirmed order. In order to verify the objection photographic proof will be required.</p>');

