INSERT INTO `testimonila` (`testimonial_id`, `name`, `profile_link`, `star_rating`, `image`, `image_tag`, `comment`) VALUES
(1, 'Hazzel Ben', 'Operation Manager at Savvy Cosmetic', '5', 'Hazzel Ben.jpg', 'Person One', 'I reached out to PremiumBoxes! Via Facebook for some gift boxes a few days ago, Emma Meaghan helps me since day one to put my order together. Their designers are professional, and the boxes that I received were flawless, just loved the design and colors scheme. I would highly recommend them!'),
(2, 'Liza Wilson', 'Founder at GreciousLady Organization. NYC', '5', 'Liza Wilson.jpg', 'Person Two', 'PremiumBoxes --- just fantastic!!! I rarely write reviews but felt, that I should give credit where credit is due. It was really easy to place the order, support staff was supportive, they help me to finalize the packaging style and color scheme etc. and it means a lot to me, And the best thing was, the package arrived within the following week, even in this pandemic situation. The quality of the boxes were flawless!! My new partner for a long time. Well done PremiumBoxes!!'),
(4, 'Steve Jason', 'Co-Founder and CEO at Megagifts, IL', '5', 'Steve Jason.jpg', 'Person Three', 'PremiumBoxes made specially customized luxuries gift Boxes for my sister’s marriage and I am glad that guests loved it. Their support staff was really co-operative. I made numerous changes in the design and the color scheme. The lady their named Emma Meaghan war really courteous she helped me in all the designing process and kept me updated. Two weeks later I received my order and everything was up-to mark. Thank You PremiumBoxes! 5 stars for PremiumBoxes.'),
(7, 'Jeorge Nick', 'Co-Founder at Devoured Foods, NYC', '4', 'Jeorge Nick.jpg', 'Person Four', 'Smooth process - solid product, called them up to place the order over the phone call as it was my first time, Jessie Ford was very helpful in designing the packaging and order was delivered within the next 7 days which was bit surprise for me. Product was solid and works well straight out of the box. I highly appreciate PremiumBoxes and the team.'),
(8, 'Vanessa T. Davis', 'Master Builder Design Services', '5', 'Vanessa T. Davis.jpg', 'edit', 'It was really amazing experience to order customized boxes online! I searched numerously to find an authentic company where I can make the order, I found premiumboxes and I glad that I found premiumboxes, the person Austin Ben was really helpful. The thing I like most about them that they have highly skilled professional staff who understands the requirements of client and creates a product that exceeds expectation. I was astonished when I received my order before the expected time. I will highly recommend premiumboxes to all individuals who are looking for custom boxes. Highly appreciated!');

